/**
 * Generate Runway firewall config.
 *
 * Data source: https://docs.dev.runwayml.com/guides/setup/
 *
 * Runway is an AI-powered creative platform for video generation.
 * Uses Bearer token authentication.
 * Only unrestricted permissions for now.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.dev.runwayml.com/guides/setup/";
// Token format not publicly documented; using generic placeholder
const PLACEHOLDER_VALUE = "Vm0PlaceHolder00000000000000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Runway API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:runway",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const runwayFirewall: FirewallConfig = {",
    '  name: "runway",',
    '  description: "Runway API",',
    "  placeholders: {",
    `    RUNWAY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.dev.runwayml.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.RUNWAY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "unrestricted",',
    '          description: "Allow all endpoints",',
    '          rules: ["ANY /{path*}"],',
    "        },",
    "      ],",
    "    },",
    "  ],",
    "};",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Runway firewall config...");
  const ts = generateTypeScript();
  writeOutput("runway", ts, import.meta.dirname);
}
